// // This module compares two single-bit inputs, in1 and in2, and produces a one-bit output, signIfComp. The output indicates the result of the comparison: if in1 is less than in2, signIfComp is set to 1; if in2 is less than in1, signIfComp is set to 0; and if both inputs are equal, signIfComp is also set to 1, indicating a non-positive comparison.
module top_module(in1,in2,signIfComp);input in1,in2;
output reg signIfComp;
always@(in1 or in2)
begin
if(in1>in2)
signIfComp=1;
else if(in2>in1)
signIfComp=0;
else
signIfComp=1;
end
endmodule
